from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Convert a list of triples about a city (or related entities) into a single fluent sentence."""
    if not triples:
        return ""

    # Identify the main subject (most common subject in triples)
    from collections import Counter
    subjects = [t.subject for t in triples]
    subject_counts = Counter(subjects)
    main_subject = subject_counts.most_common(1)[0][0] if subject_counts else ""

    # Build sentence parts efficiently
    sentence_parts = []
    clauses = []

    # First clause: subject with type
    type_objects = [t.object for t in triples if t.predicate == "type"]
    if type_objects:
        sentence_parts.append(f"{main_subject} is a {type_objects[0]}")
    else:
        sentence_parts.append(main_subject)

    # Collect location information
    location_parts = []
    for t in triples:
        if t.predicate == "country":
            location_parts.append(f"in {t.object}")
        elif t.predicate == "state":
            location_parts.append(f"state of {t.object}")
        elif t.predicate == "isPartOf":
            location_parts.append(f"part of {t.object}")

    if location_parts:
        if len(location_parts) == 1:
            sentence_parts.append(f", {location_parts[0]}")
        else:
            sentence_parts.append(f", {' and '.join(location_parts)}")

    # Collect demographic information
    demo_parts = []
    for t in triples:
        if t.predicate == "populationTotal":
            demo_parts.append(f"population of {t.object}")
        elif t.predicate == "populationDensity":
            demo_parts.append(f"population density of {t.object}")
        elif t.predicate == "populationMetro":
            demo_parts.append(f"metro population of {t.object}")
        elif t.predicate == "demonym":
            demo_parts.append(f"residents called {t.object}")

    if demo_parts:
        if len(demo_parts) == 1:
            sentence_parts.append(f", with a {demo_parts[0]}")
        else:
            sentence_parts.append(f", with {' and '.join(demo_parts)}")

    # Collect area information
    area_parts = []
    for t in triples:
        if t.predicate == "areaTotal":
            area_parts.append(f"total area of {t.object}")
        elif t.predicate == "areaOfLand":
            area_parts.append(f"land area of {t.object}")
        elif t.predicate == "areaOfWater":
            area_parts.append(f"water area of {t.object}")

    if area_parts:
        if len(area_parts) == 1:
            sentence_parts.append(f", with a {area_parts[0]}")
        else:
            sentence_parts.append(f", with {' and '.join(area_parts)}")

    # Collect administrative information
    admin_parts = []
    for t in triples:
        if t.predicate == "leader":
            admin_parts.append(f"led by {t.object}")
        elif t.predicate == "governmentType":
            admin_parts.append(f"{t.object} government")
        elif t.predicate == "leaderTitle":
            admin_parts.append(f"led by a {t.object}")

    if admin_parts:
        if len(admin_parts) == 1:
            sentence_parts.append(f", {admin_parts[0]}")
        else:
            sentence_parts.append(f", {' and '.join(admin_parts)}")

    # Collect relative clauses (capital, largestCity, countySeat)
    relative_parts = []
    for t in triples:
        if t.predicate == "capital":
            relative_parts.append(f"where the capital is {t.object}")
        elif t.predicate == "largestCity":
            relative_parts.append(f"with largest city {t.object}")
        elif t.predicate == "countySeat":
            relative_parts.append(f"with county seat {t.object}")

    if relative_parts:
        if len(relative_parts) == 1:
            clauses.append(relative_parts[0])
        else:
            clauses.append(f", {' and '.join(relative_parts)}")

    # Collect other information
    other_parts = []
    for t in triples:
        if t.predicate == "elevationAboveTheSeaLevel":
            other_parts.append(f"elevation of {t.object}")
        elif t.predicate == "timeZone":
            other_parts.append(f"{t.object} time zone")
        elif t.predicate == "utcOffset":
            other_parts.append(f"UTC offset {t.object}")
        elif t.predicate == "areaCode":
            other_parts.append(f"area code {t.object}")
        elif t.predicate == "postalCode":
            other_parts.append(f"postal code {t.object}")
        elif t.predicate == "language":
            other_parts.append(f"speaks {t.object}")
        elif t.predicate == "ethnicGroup":
            other_parts.append(f"includes {t.object}")

    if other_parts:
        if len(other_parts) == 1:
            sentence_parts.append(f", with a {other_parts[0]}")
        else:
            sentence_parts.append(f", with {' and '.join(other_parts)}")

    # Combine all parts with relative clauses at the end
    result = ''.join(sentence_parts)
    if clauses:
        result += ''.join(clauses)

    return result + "."

# EVOLVE-BLOCK-END

